function humanReadableBytesF(bytes: number): string {
  const units: string[] = ['B', 'KB', 'MB', 'GB', 'TB']
  let value = bytes
  let i = 0
  while (value >= 1024 && i < units.length - 1) {
    value = value / 1024
    i++
  }
  const rounded = Math.round(value * 100) / 100
  return rounded.toString() + ' ' + units[i]
}

