function luhnChecksumValidF(digits: string): boolean {
  let sum = 0
  let alt = false
  for (let i = digits.length - 1; i >= 0; i--) {
    let d = digits.charCodeAt(i) - 48
    if (d < 0 || d > 9) {
      return false
    }
    if (alt) {
      d = d * 2
      if (d > 9) {
        d = d - 9
      }
    }
    sum += d
    alt = !alt
  }
  return sum % 10 === 0
}

