function sieveOfPrimesF(n: number): number[] {
  if (n < 2) {
    return []
  }
  const flags: boolean[] = new Array<boolean>(n + 1).fill(true)
  flags[0] = false
  flags[1] = false
  for (let p = 2; p * p <= n; p++) {
    if (flags[p]) {
      for (let m = p * p; m <= n; m += p) {
        flags[m] = false
      }
    }
  }
  const primes: number[] = []
  for (let i = 2; i <= n; i++) {
    if (flags[i]) {
      primes.push(i)
    }
  }
  return primes
}

