function populationStdDevF(values: number[]): number {
  if (values.length === 0) {
    return 0
  }
  let sum = 0
  for (let i = 0; i < values.length; i++) {
    sum += values[i]
  }
  const mean = sum / values.length
  let acc = 0
  for (let j = 0; j < values.length; j++) {
    const diff = values[j] - mean
    acc += diff * diff
  }
  return Math.sqrt(acc / values.length)
}

